package com.nv.commons.dao;import java.math.BigDecimal;import java.sql.Connection;import java.sql.Timestamp;import java.util.List;import com.nv.commons.dto.ServerInfoEntity;import com.nv.commons.model.database.DBQueryRunner;/** * Title: com.neutec.nepal.common.dao.ServerInfoDAO<br> * Description: AP資訊DAO */public class ServerInfoDAO {	public static List<ServerInfoEntity> findAll(Connection conn) throws Exception {		return DBQueryRunner.getBeanList(conn, ServerInfoEntity.class, "SELECT * FROM SERVERINFO ORDER BY ID");	}	public static boolean isExist(Connection conn, String ip) throws Exception {		return DBQueryRunner			.getNumberWithDefault(conn, "SELECT count(id) FROM SERVERINFO WHERE ip = ? ", BigDecimal.ZERO, ip)			.intValue() > 0;	}	public static int updateStatusByIP(Connection conn, String ip, int serverType, boolean isActive) throws Exception {		if (serverType == -1) {			return DBQueryRunner.update(conn,				"UPDATE SERVERINFO SET IS_ACTIVE=?, UPDATE_TIME = SYSTIMESTAMP WHERE IP=?", isActive, ip);		} else {			return DBQueryRunner.update(conn,				"UPDATE SERVERINFO SET IS_ACTIVE=?, UPDATE_TIME = SYSTIMESTAMP WHERE IP=? AND SERVER_TYPE = ?",				isActive, ip, serverType);		}	}	public static List<ServerInfoEntity> findByUpdateTime(Connection conn, Timestamp updateTime) throws Exception {		return DBQueryRunner.getBeanList(conn, ServerInfoEntity.class,			"SELECT * FROM SERVERINFO WHERE UPDATE_TIME > ? ", updateTime);	}}